let oo : string = "Mukanee"
let shi : string = "Mae"
let ma : string = "Shika"
let yuko : string = "48"

if (oo == shi || ma == oo) {
  yuko = shi + ma + yuko
} else if (("47 + 1") == yuko && !(ma != shi)) {
  yuko = yuko + oo + shi
} else if (oo != shi && ma != yuko) {
  yuko = shi + ma + oo
} else {
  yuko = oo + shi + ma
}

